//==========================
// saxpy for 5000 elements
// after copying the instr.csv, run with:
// > python .\sim_generator.py .\instrs.csv 5000 VECTOR_LANES
// where VECTOR_LANES the number of the RTLs vector lanes
//==========================
//load conditions
vld, v1, #0
//load x
vld, v2, #640
//load y
vld, v3, #1280
// compare cond
vseq, v1, v1, v1
// mul a*x
vmul, v4, v3, v3
// add a*x+y
vadd, v4, v4, v2
// store result
vsw, v4, #2560

//==========================
// Dot product of 2 arrays with 5000 el
// after copying the instr.csv, run with:
// > python .\sim_generator.py .\instrs.csv 5000 VECTOR_LANES
// where VECTOR_LANES the number of the RTLs vector lanes
//==========================
//v0 holds the total sum -> zero it
vandi, v0, v0, #0
//load the first array
vld, v1, #0
//load the second array
vld, v2, #2048
//calculate their product
vmul, v3, v1, v2
//reduce the result
vradd, v4, v3
//add it to sum
vadd, v4, v0

//==========================
// FIR filter for 5000 el
// after copying the instr.csv, run with:
// > python .\sim_generator.py .\instrs.csv 5000 VECTOR_LANES
// where VECTOR_LANES the number of the RTLs vector lanes
//==========================
//load third tap (-2) & mul
vld, v2, #8
vslli, v2, v2, #2
//load second tap (-1) & mul
vld, v3, #12
vmul, v3, v3, #3
//-------------------------
//add the first two
vadd, v5, v3, v2
//-------------------------
//load first tap & mul
vld, v4, #16
vmul, v4, v4, #3
//load first tap (-4)
vld, v0, #0
//-------------------------
//add two more
vadd, v6, v4, v0
//-------------------------
//load second tap (-3)
vld, v1, #4
//-------------------------
// add first sum and new vector
vadd, v5, v5, v1
// final addition
vadd, v5, v5, v6

//==========================
// vvadd for 5000 elements
// after copying the instr.csv, run with:
// > python .\sim_generator.py .\instrs.csv 5000 VECTOR_LANES
// where VECTOR_LANES the number of the RTLs vector lanes
//==========================
//load the first array
vld, v0, #0
//load the second array
vld, v1, #2048
//add the result
vadd, v2, v0, v1

